// Validate URL and extract metadata
// Handle both flat payload and n8n-wrapped payload (body key)
const rawInput = $input.first().json;
const payload = rawInput.body || rawInput;

const url = payload.url || '';
const importId = payload.importId || '';
const callbackUrl = payload.callbackUrl || '';
const callbackSecret = payload.callbackSecret || '';
let platform = payload.platform || 'blog';

if (!url || !importId || !callbackUrl) {
  throw new Error('Missing required fields: url, importId, callbackUrl');
}

// Validate URL using regex (new URL() is not available in n8n Code sandbox)
if (!/^https?:\/\//i.test(url)) {
  throw new Error('Invalid URL: must start with http:// or https://');
}

// Extract domain without new URL()
const domainMatch = url.match(/^https?:\/\/(?:www\.)?([^/\s]+)/i);
const domain = domainMatch ? domainMatch[1] : '';

// Override platform detection from URL patterns
if (url.includes('youtube.com/watch') || url.includes('youtu.be/')) {
  platform = 'youtube';
}

// Extract YouTube video ID if applicable
let videoId = null;
if (platform === 'youtube') {
  const ytMatch = url.match(/[?&]v=([^&#]+)/) || url.match(/youtu\.be\/([^?&#]+)/);
  videoId = ytMatch ? ytMatch[1] : null;
  if (!videoId) {
    throw new Error('Could not extract YouTube video ID from URL: ' + url);
  }
}

return {
  json: {
    url,
    importId,
    callbackUrl,
    callbackSecret,
    platform,
    domain,
    videoId
  }
};

// Extract YouTube transcript URL from ytInitialPlayerResponse
const pageHtml = $input.first().json.data || $input.first().json.body || '';
const prev = $('Validate URL').first().json;

if (!pageHtml || pageHtml.length < 500) {
  return {
    json: {
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      importId: prev.importId,
      error: 'Failed to fetch YouTube page',
      rawContent: ''
    }
  };
}

// Extract video title
const titleMatch = pageHtml.match(/<title[^>]*>([^<]+)<\/title>/i);
const videoTitle = titleMatch ? titleMatch[1].replace(' - YouTube', '').trim() : 'YouTube Recipe';

// Extract ytInitialPlayerResponse JSON blob
const playerMatch = pageHtml.match(/var ytInitialPlayerResponse\s*=\s*(\{.+?\});\s*(?:var |const |let |<\/script>)/s);
if (!playerMatch) {
  return {
    json: {
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      importId: prev.importId,
      url: prev.url,
      videoTitle,
      transcriptUrl: null,
      error: 'Could not find ytInitialPlayerResponse in page'
    }
  };
}

let playerData;
try {
  playerData = JSON.parse(playerMatch[1]);
} catch (e) {
  return {
    json: {
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      importId: prev.importId,
      url: prev.url,
      videoTitle,
      transcriptUrl: null,
      error: 'Failed to parse ytInitialPlayerResponse: ' + e.message
    }
  };
}

// Navigate to caption tracks
const captionsRenderer = playerData?.captions?.playerCaptionsTracklistRenderer;
const tracks = captionsRenderer?.captionTracks;

if (!tracks || tracks.length === 0) {
  return {
    json: {
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      importId: prev.importId,
      url: prev.url,
      videoTitle,
      transcriptUrl: null,
      error: 'No caption tracks found for this video'
    }
  };
}

// Prefer English, fall back to first available
const englishTrack = tracks.find(t => t.languageCode === 'en' || t.languageCode === 'en-US');
const track = englishTrack || tracks[0];
const baseUrl = track.baseUrl;

if (!baseUrl) {
  return {
    json: {
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      importId: prev.importId,
      url: prev.url,
      videoTitle,
      transcriptUrl: null,
      error: 'Caption track has no baseUrl'
    }
  };
}

const transcriptUrl = baseUrl + '&fmt=json3';

return {
  json: {
    url: prev.url,
    importId: prev.importId,
    callbackUrl: prev.callbackUrl,
    callbackSecret: prev.callbackSecret,
    videoTitle,
    transcriptUrl,
    error: null
  }
};

// Build transcript text from YouTube json3 caption format
const transcriptData = $input.first().json;
const prev = $('Extract Transcript URL').first().json;

if (prev.error) {
  // Pass through the error
  return {
    json: {
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      importId: prev.importId,
      error: prev.error,
      rawContent: ''
    }
  };
}

// json3 format: { events: [{ segs: [{ utf8: 'text' }], tStartMs, dDurationMs }] }
let transcriptText = '';

if (transcriptData && transcriptData.events) {
  const segments = [];
  for (const event of transcriptData.events) {
    if (!event.segs) continue;
    const text = event.segs
      .map(s => s.utf8 || '')
      .join('')
      .replace(/\n/g, ' ')
      .trim();
    if (text) segments.push(text);
  }
  transcriptText = segments.join(' ');
} else {
  return {
    json: {
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      importId: prev.importId,
      error: 'No transcript events found',
      rawContent: ''
    }
  };
}

// Trim to 6000 chars for GPT context
const trimmedTranscript = transcriptText.substring(0, 6000);

return {
  json: {
    url: prev.url,
    importId: prev.importId,
    callbackUrl: prev.callbackUrl,
    callbackSecret: prev.callbackSecret,
    videoTitle: prev.videoTitle,
    transcriptText: trimmedTranscript
  }
};

