// Format GPT response for callback
const gptResponse = $input.first().json;
const prevData = $('Extract JSON-LD').first().json;

let parsedRecipe;
try {
  // The GPT response might be in .message.content or directly in the output
  const content = gptResponse.message?.content || gptResponse.text || JSON.stringify(gptResponse);
  parsedRecipe = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  return {
    json: {
      callbackUrl: prevData.callbackUrl,
      callbackSecret: prevData.callbackSecret,
      importId: prevData.importId,
      error: 'Failed to parse GPT response',
      rawContent: prevData.rawText
    }
  };
}

if (parsedRecipe.error) {
  return {
    json: {
      callbackUrl: prevData.callbackUrl,
      callbackSecret: prevData.callbackSecret,
      importId: prevData.importId,
      error: parsedRecipe.error,
      rawContent: prevData.rawText
    }
  };
}

return {
  json: {
    callbackUrl: prevData.callbackUrl,
    callbackSecret: prevData.callbackSecret,
    importId: prevData.importId,
    recipe: parsedRecipe,
    rawContent: prevData.rawText,
    rawMetadata: { title: parsedRecipe.title, url: prevData.url, source: 'gpt' }
  }
};

// Format JSON-LD result for callback
const data = $input.first().json;

return {
  json: {
    callbackUrl: data.callbackUrl,
    callbackSecret: data.callbackSecret,
    importId: data.importId,
    recipe: data.parsedRecipe,
    rawContent: data.rawText,
    rawMetadata: { title: data.parsedRecipe.title, url: data.url, source: 'json-ld' }
  }
};
